var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"마왕의 난세 아래 인류는 사라지고, 겨울만이 남는다.","JPN":"魔王の乱世のもとに人類は消え、冬だけが残る。","ENG":"Under the Demon Lord's age of chaos, humanity vanishes, leaving only winter behind.","TWN":"在魔王的亂世下，人類消失，只剩冬季。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"미래를 속삭이는 황금나무는 부러진 채 침묵한다.","JPN":"未来を囁く黄金の木は折れたまま沈黙する。","ENG":"The Golden Tree that whispers of the future stands broken, silent.","TWN":"輕聲述說未來的黃金樹，斷裂後陷入沉默。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그것이 세상의 끝이었다.","JPN":"それが世界の終わりだった。","ENG":"That was the end of the world.","TWN":"那便是世界的終結。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"분명 그러했을 텐데.","JPN":"そのはずだったが。","ENG":"It should have been.","TWN":"原本應該如此。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"모든 것을 얼어붙게 하는 겨울바람이 그치고, 땅에서 싹이 났다.","JPN":"すべてを凍らせる冬の風が止み、大地から芽が出た。","ENG":"The winter wind that freezes everything comes to a halt, and sprouts emerge from the earth.","TWN":"凍結一切的寒風靜止，土地萌芽。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"새로운 해가 뜨고, 새로운 생명이 움튼다.","JPN":"新しい日が昇り、新しい命が芽生える。","ENG":"A new sun rises, and new life begins to stir.","TWN":"新日升起，孕育著新生命。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그 중심에는 황금나무를 감싸 안은 한 소녀가 있었다.","JPN":"その中心には黄金の木を抱いた一人の少女がいた。","ENG":"And at its center is a girl embracing the Golden Tree.","TWN":"在這中間，有個擁抱黃金樹的少女。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...무슨 일이십니까?","JPN":"……どうされましたか？","ENG":"...What brings you here?","TWN":"……發生什麼事了？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아를 만나고 싶어요.","JPN":"エクレシアに会いたいんです。","ENG":"I want to meet Ecclesia.","TWN":"我想見艾可露西亞。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"곧 돌아올 테니, 잠시 이곳에서 기다리시지요.","JPN":"すぐ戻りますので、しばらくここでお待ちください。","ENG":"She will be back soon, so please wait here for a while.","TWN":"她很快就回來，你先在這裡等她吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"에클레시아는 지금 자신이 가장 좋아하는 곳에서 기도 중입니다.","JPN":"エクレシアは今、自分が一番好きな場所で祈りを捧げております。","ENG":"Ecclesia is praying right now in the place she loves most.","TWN":"艾可露西亞現在在她最喜愛的地方祈禱。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어디에서요?","JPN":"どこでですか？","ENG":"Where?","TWN":"那在哪裡？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원의 가장 양지 바른 자리. 황금나무의 언덕이랍니다.","JPN":"楽園で最も日当たりの良い場所。黄金の木の丘です。","ENG":"The sunniest place in the Promised Land. The hill of the Golden Tree.","TWN":"樂園最陽光充足的地方，黃金樹的小丘。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신이 에클레시아의 아버지... 맞죠?","JPN":"あなたがエクレシアのお父さん……ですよね？","ENG":"You are Ecclesia's father... aren't you?","TWN":"你是艾可露西亞的父親……對吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 아이에 대해 얼마나 알고 있나요?","JPN":"あの子についてどこまで知っていますか？","ENG":"How much do you know about her?","TWN":"你對那孩子瞭解多少？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"당신이 가진 <color=#ffd34c>다른 존재</color>의 기억보다 많은 걸 알고 있지요.","JPN":"あなたの持つ<color=#ffd34c>他の存在</color>の記憶よりも多くのことを知っております。","ENG":"More than the memories of the <color=#ffd34c>other being</color> within you.","TWN":"我知道的比你對<color=#ffd34c>其他存在</color>的記憶還多。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...네퀴티아를 알고 있어?","JPN":"……ネキティアを知ってるの？","ENG":"...You know Nequitia?","TWN":"……你認識莉奎蒂亞？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"저는 많은 걸 알고 있습니다.","JPN":"私が知っていることはたくさんあります。","ENG":"I know many things.","TWN":"我知道很多事。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"당신 안에 두 사람의 운명이 묶여 있다는 것도-","JPN":"あなたの中で二人分の運命が絡み合っていることも……","ENG":"Including the fact that the fates of two people are bound within you...","TWN":"我也知道你體內交織著兩人的命運—"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그 둘이 서로를 받아들이지 못한 채 외면하고 있다는 사실도요.","JPN":"その二人がお互いを受け入れられないまま、目を背けているという事実もです。","ENG":"And that neither can accept the other, so both choose to look away.","TWN":"兩人無法接受彼此、互相迴避。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그렇다면 우리가 어쩌다 여기에 오게 됐는지도 알아?","JPN":"……じゃあ、私たちがどうやってここに来たのかも知ってるの？","ENG":"...Then do you also know how we ended up here?","TWN":"……那你知道我們怎麼會來到這裡嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"외지인이 이곳에 당도하는 이유는 단 하나.","JPN":"よそ者がここにたどり着く理由はたった一つ。","ENG":"There is only one reason outsiders arrive here.","TWN":"外地人來到這裡，只有一個原因。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원이 그러길 바랐기 때문입니다.","JPN":"楽園がそれを望んだからです。","ENG":"Because the Promised Land wished it so.","TWN":"樂園希望如此。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러니, 당신도 낙원에서의 삶이 만족스러우셨으면 좋겠군요.","JPN":"ですから、あなたも楽園での生活に満足していただけたら幸いです。","ENG":"So I hope you, too, will find life in the Promised Land fulfilling.","TWN":"所以，希望你也可以滿意在樂園的生活。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"응, 간만의 기적 같은 평화를 만끽하고 있어.","JPN":"うん、久しぶりに奇跡のような平和を満喫してる。","ENG":"Yes, I'm enjoying a miracle-like peace I haven't felt in a long time.","TWN":"嗯，我很享受如奇蹟般的和平。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"무엇보다 엄마를 이렇게 다시 만날 수 있었다는 것에, 분에 넘치는 감사를 느껴.","JPN":"何よりこうやってお母さんにまた会えたことは、私にはもったいないくらいだよ。","ENG":"More than anything, I feel an undeserved gratitude for being able to see my mother again like this.","TWN":"最感激的是我能再次見到母親。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 돌아가야 해. 언제까지고 기적을 꿈꾸고만 있을 순 없으니까.","JPN":"でも戻らないと。いつまでも奇跡を夢見ているわけにはいかないから。","ENG":"But I have to go back. I can't keep dreaming of miracles forever.","TWN":"但我還是得回去。我不能永遠沉溺於奇蹟中。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원은 뜻이 있는 자의 길을 막지 않습니다.","JPN":"楽園は意志ある者の行く手を阻むことはありません。","ENG":"The Promised Land does not bar the way of those with resolve.","TWN":"樂園不會阻礙有志者的未來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하지만 그 아이를 끌어들이진 마십시오.","JPN":"ですが、あの子を巻き込まないでください。","ENG":"But do not drag that child into it.","TWN":"但別把那孩子牽扯進來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아를 어떻게 할 셈이야?","JPN":"エクレシアをどうするつもり？","ENG":"What are you planning to do with Ecclesia?","TWN":"你打算怎麼處理艾可露西亞？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아무것도요.","JPN":"どうもしません。","ENG":"Nothing.","TWN":"什麼也不做。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아비 된 자로서, 오랜 여정에 지친 그 아이가 편히 쉬게 해주고 있을 뿐입니다.","JPN":"父として、長旅に疲れたあの子がゆっくり休めるようにしているだけです。","ENG":"As her father, I am only letting that child, weary from a long journey, rest in peace.","TWN":"作為父親，只想讓這個在漫長旅途中感到疲憊的孩子能好好休息。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온이란 마왕이 머잖아 우리 세계에 올 거야.","JPN":"タギリオンっていう魔王が、間もなく私たちの世界にやって来る。","ENG":"The Demon Lord Thagirion will come to our world before long.","TWN":"魔王塔基里翁不久之後就會來到我們的世界。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신이 엘리시온 출신이라면, 마왕이 얼마나 위험한지는 알고 있겠지. 그래서 도움이 필요해.","JPN":"あなたがエリシオン出身なら、魔王がどれほど危険な存在か分かっているでしょう？　だから手を借りたいの。","ENG":"If you're from Elysion, then you know how dangerous a Demon Lord is. That's why I need your help.","TWN":"若你來自艾利森，應該知道魔王有多危險。所以我們需要幫助。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그래서, 그 마왕을 막기 위해 에클레시아를 제물로 쓰겠다는 말인가요?","JPN":"それで、その魔王を止めるためにエクレシアを生贄にするというのですか？","ENG":"So you mean to use Ecclesia as a sacrifice to stop that Demon Lord?","TWN":"那麼，你打算用艾可露西亞作為祭品，阻止魔王？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"제물이 아니야. 뜻이 같기에 힘을 모으려는 거지.","JPN":"生贄じゃない。同じ目的を持つ者同士、力を合わせるの。","ENG":"Not a sacrifice. We're trying to join forces because our purpose is the same.","TWN":"不是祭品。因為我們理念一樣，想一起合作。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"정작 본인은 자신이 우리와 함께 싸웠다는 기억을 잃은 것 같았지만... 내가 어떻게든 도와주면 기억해낼 거야.","JPN":"当の本人は私たちと共に戦った記憶を失っているようだけど……私がどうにかして手伝ってあげれば、思い出せるはずだよ。","ENG":"Though it seemed like she herself had lost the memory of ever fighting alongside us... if I help her somehow, she'll remember.","TWN":"雖然她好像忘了與我們並肩作戰的記憶……無論如何，我都會幫她想起來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"돕는다고요?","JPN":"手伝う？","ENG":"Help her?","TWN":"幫她？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그 아이는 아주 오랫동안 타기리온을 막기 위한 싸움을 해왔습니다.","JPN":"あの子はとても長い間タギリオンを止めるために戦ってきました。","ENG":"That child has fought for a very long time to stop Thagirion.","TWN":"那孩子長久以來一直在對抗塔基里翁。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"망집이 된 채 영겁의 세월 동안 수많은 세계를 떠돌며, 그 영혼은 망가질대로 망가졌지요.","JPN":"それが妄執となり、永劫の時の中で数々の世界を彷徨いながら、その魂は完全に壊れてしましました。","ENG":"As a lingering obsession, she wandered countless worlds through an eternity, and her soul was damaged beyond repair.","TWN":"徜徉在永劫的歲月裡，她的靈魂早已支離破碎。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그녀를 진정으로 돕고 싶다면, 더 이상 그녀를 분쟁에 끌어들이지 마십시오.","JPN":"本当に彼女を助けたいのなら、これ以上彼女を争いに巻き込まないでいただきたい。","ENG":"If you truly wish to help her, then do not drag her into conflict any longer.","TWN":"若你真的想幫助她，不要再把她捲入紛爭。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...무슨 말을 하고 싶은진 알겠어.","JPN":"……言いたいことは分かった。","ENG":"...I understand what you're trying to say.","TWN":"……我明白你的意思了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 그녀의 도움이 없으면, 우리 세계도 당신의 세계처럼 무너지고 말 거야.","JPN":"でも彼女の助けがなければ、私たちの世界もあなたの世界のように壊れてしまうの。","ENG":"But without her help, our world will collapse just like yours did.","TWN":"但沒有她，我們的世界也會跟你的世界一樣崩壞。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"세계의 종말은 정해진 수순입니다.","JPN":"世界の終末は最初から決まっているのです。","ENG":"The end of a world is an ordained course.","TWN":"世界的終結，是既定過程。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"더 이상 필요치 않은 나뭇가지를 잘라내는 과정과 같죠. 몇 번을 잘라도 다음 가지가 다시 자랄 테니까요.","JPN":"必要のなくなった枝を剪定するのと同じです。何度切っても、また次の枝は生えてきますから。","ENG":"It is like pruning a branch that is no longer needed. No matter how many times you cut it, the next branch will grow again.","TWN":"就像修剪不再需要的樹枝。就算剪了好幾次，下個枝條又會繼續生長。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"과연 에클레시아도 그렇게 생각할까?","JPN":"エクレシアもそう思うかな？","ENG":"Do you think Ecclesia feels the same way?","TWN":"艾可露西亞會這麼想嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"자신의 영혼을 망가뜨리면서까지 영겁의 세월을 싸울 정도의 긍지를 가진 사람이, 지쳤다는 이유로 포기한다고?","JPN":"自分の魂が壊れるまで永劫の時を戦い続けるほど誇りを持ってる人が、疲れたって理由だけで諦める？","ENG":"Someone with enough pride to fight through an eternity at the cost of her own soul would give up just because she's tired?","TWN":"一個願為永恆歲月奮戰、靈魂破碎的人，會因為疲憊而放棄嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇게 멋대로 기억에 족쇄를 채우고, 가짜 삶을 살게 할 셈이야?!","JPN":"そうやって勝手に記憶に鎖をかけて、偽の人生を歩ませるつもりなの！？","ENG":"You're going to shackle her memories however you please and force her to live a false life?!","TWN":"你要這樣恣意扣上記憶的枷鎖，讓她過著虛假的生活？！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그것이 그 아이의 영혼을 구원할 유일한 방법이니까요.","JPN":"それがあの子の魂を救う唯一の方法ですから。","ENG":"Because that is the only way to save her soul.","TWN":"這是拯救她靈魂唯一的方法。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"낙원은 주민들의 소망을 이뤄준다더군.","JPN":"楽園は住民の願いを叶えてくれるらしいね。","ENG":"I hear the Promised Land grants the wishes of its residents.","TWN":"樂園會實現居民的願望。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그림자 모르스를 당신이 사랑하던 시절의 에클레시아로 되돌리는 게, 당신의 소망인 건가?","JPN":"シャドウのモールスをあなたが愛していた頃のエクレシアに戻すのが、あなたの願いなの？","ENG":"So is your wish to return Shadow Mors to the Ecclesia you loved?","TWN":"把暗影莫爾斯恢復到你所愛的艾可露西亞時期，是你的願望嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아뇨. 제 소망은...","JPN":"いいえ。私の願いは……","ENG":"No. My wish is–","TWN":"不，我的願望是……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지!","JPN":"お父様！","ENG":"Father!","TWN":"父親！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"에클레시아? 벌써 돌아온 거니?","JPN":"エクレシア？　もう帰ってきたのかい？","ENG":"Ecclesia? Back already?","TWN":"艾可露西亞？你回來啦？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이것 보셔요, 아버지.","JPN":"ご覧ください、お父様。","ENG":"Look, Father.","TWN":"父親，你看這個。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"하늘에서 이런 게 떨어졌사옵니다.","JPN":"空からこんなものが降ってきました。","ENG":"This fell from the sky.","TWN":"天空降下這種東西。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이건... 눈결정? 손에 올려도 녹지 않네.","JPN":"これは……雪の結晶？　手に乗せても溶けないね。","ENG":"A snowflake...? It doesn't melt even in my hand.","TWN":"這是……雪晶？放在手上也不融化呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"앗? 손님이 와 계신 줄도 모르고...","JPN":"あっ？　お客様がいらしているとは知らず……","ENG":"Oh? I didn't even realize we had a guest...","TWN":"啊？我沒注意到有客人……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"얼른 과일을 따오겠사옵니다!","JPN":"急いで果物を採ってまいります！","ENG":"I'll hurry and gather some fruit!","TWN":"我馬上去摘水果回來！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"괜찮다. 금방 돌아가실 거야.","JPN":"大丈夫。すぐお帰りになるよ。","ENG":"That won't be necessary. She'll be leaving soon.","TWN":"沒事，她很快就會回來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아... 그렇습니까?","JPN":"あ……そうなのですか？","ENG":"Ah... is that so?","TWN":"啊……是嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이봐, 난...!","JPN":"ちょっと、私は……！","ENG":"Hey, I–!","TWN":"那個，我……！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하지만 우리집 손님을 빈손으로 돌려보낼 순 없으니...","JPN":"でも、お客様を手ぶらでお帰しするわけにはいかないから……","ENG":"But we cannot send a guest of our home away empty-handed...","TWN":"但不能讓家裡的客人空手回去……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"오늘 수확은 이분과 함께 다녀오려무나. 괜찮겠지?","JPN":"今日の収穫はこの方と一緒に行っておいで。いいね？","ENG":"Why don't you accompany her and bring in today's harvest together? Is that acceptable to you?","TWN":"你今天就和這位一起去採收吧。可以嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"네! 그럼 장대 가위를 가져오겠나이다!","JPN":"はい！　では、高枝切りバサミを持ってまいります！","ENG":"Yes! Then I'll go fetch the pole pruners!","TWN":"好！那我去拿長柄剪刀！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...못 만나게 막을 줄 알았는데, 뜻밖이네.","JPN":"……会えないように邪魔をされると思ったのに、意外だったよ。","ENG":"...I thought you'd try to stop me from meeting her. This is unexpected.","TWN":"……我還以為你會阻止我見她，真意外。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원의 사제는 분쟁의 씨앗을 심지 않습니다.","JPN":"楽園の司祭は紛争の種をまいたりしません。","ENG":"A priest of the Promised Land does not sow the seeds of conflict.","TWN":"樂園的祭司不會播下紛爭的種子。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"저의 뜻은 충분히 전달했으니, 여기서부턴 당신과 그 아이의 선택에 맡겨야겠지요.","JPN":"私の意志はしっかりとお伝えしました。ここからはあなたとあの子の選択に託すしかありません。","ENG":"I have conveyed my will clearly enough, so from here on, I must leave it to your choice and that child's.","TWN":"我已經充分傳達我的意思了，接下來就交給你和那孩子自己選擇吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하나만 약속해주십시오.","JPN":"一つだけ約束してください。","ENG":"Promise me just one thing.","TWN":"我只想請你答應我一件事。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"오늘 안으로 그 아이를 설득하지 못한다면, 더는 그 아일 괴롭히지 않겠다고 말입니다.","JPN":"今日中にあの子を説得できなかったら、もうあの子を悩ませないと。","ENG":"If you cannot persuade that child by today, then promise you will trouble her no longer.","TWN":"如果今天之內無法說服她，就別再打擾她了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"흥, 흐흥-","JPN":"ふん、ふふ～ん。","ENG":"Hn-hmm...","TWN":"哼，哼哼—"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"헉... 헉...","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"어서 올라오셔요-!","JPN":"早く来てくださーい！","ENG":"Come up quickly!","TWN":"快上來吧—！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"언덕... 엄청 잘 오르네.","JPN":"丘……ずいぶん軽々と登って行くんだね。","ENG":"You're... really good at climbing hills.","TWN":"你還……爬得真快。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"매일 오르는 길이니 당연하옵니다.","JPN":"毎日登っていますので、当然です。","ENG":"I climb this path every day, so of course I am.","TWN":"那當然了，我每天都走這條路。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그치만 다른 분과 함께 수확을 나오는 건 처음이라서, 더 즐겁사옵니다.","JPN":"でも他の方と一緒に収穫に来るのは初めてなので、もっと楽しいです。","ENG":"But it's my first time going out to harvest with someone else, so it's even more delightful.","TWN":"不過這是我第一次和別人一起出來採收，所以特別開心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그렇게가 아니옵니다! 좀 더 끝에 힘을 실어서 한 번에 자르소서!","JPN":"そうではありません！　もっと先に力を入れて、一気にお切りください！","ENG":"Not like that! Put a little more strength into the end and cut it in one go!","TWN":"不是那樣！要把力量集中在剪刀前端，一次剪斷！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이, 이렇게?","JPN":"こ、こう？","ENG":"L-like this?","TWN":"這、這樣嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_THROW"},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...받았다!","JPN":"……取りました！","ENG":"...Got it!","TWN":"……接到了！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"잘 하셨사옵니다.","JPN":"お上手です。","ENG":"Well done.","TWN":"做得很好。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하하... 높은 가지에 있는 과일은 정말 따기 힘드네.","JPN":"はは……枝の高い所にある果物って、取るのが本当に難しいんだね。","ENG":"Haha... Fruit on the high branches really is hard to pick.","TWN":"哈哈……高處的果實真的很難摘。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그냥 땅에 떨어진 과일을 가져가도 될 것 같은데 말이야.","JPN":"地面に落ちた果物をもらっても良さそうなのに。","ENG":"It feels like we could just take the fruit that's fallen to the ground.","TWN":"應該也可以撿掉在地上的果實吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"<color=#ffd34c>나무가 떨어트린 과일은 나무가 낙원에게 주는 보답이다</color>.","JPN":"<color=#ffd34c>木が落とす果物は、木から楽園への恩返しである</color>。","ENG":"<color=#ffd34c>The fruit a tree lets fall is the tree's way of repaying the Promised Land.</color>","TWN":"<color=#ffd34c>自樹上掉落的果實，是樹木獻給樂園的回禮</color>。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그러니, 건들지 않는 것이옵니다.","JPN":"だから手を出さないのでございます。","ENG":"So we mustn't touch it.","TWN":"所以不能動。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나무가 보답하는 거라고?","JPN":"木からの恩返し？","ENG":"The tree is repaying it?","TWN":"是樹的回禮？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"네. 땅이 소중한 양분을 내주었으니 그걸 열심히 키워내어 돌려주는 것입니다.","JPN":"はい。大地が大切な養分をくれたので、実をよく育てた後で返すのです。","ENG":"Yes. The earth gave it precious nourishment, so the tree diligently grows it and gives it back.","TWN":"對。土地給予珍貴的養分，樹木努力孕育果實再回報給土地。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"물론 하루가 반복되는 지금은 아무런 의미가 없는 일지도 모르지만.","JPN":"もちろん一日が繰り返されている今は何の意味もないのかもしれませんが。","ENG":"Of course, now that the same day repeats itself, perhaps it means nothing at all.","TWN":"當然，在日復一日的今天，也許已經沒有什麼意義了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"언젠가 완전해진 낙원에서, 오늘이 아닌 내일을 대비하며 살아가는 법을 잊어서는 안 되니 말입니다.","JPN":"いつか完全になる楽園で、今日ではない明日に備えて生きていく方法を忘れてはいけませんので。","ENG":"But someday, in a perfected Promised Land, we must not forget how to live in preparation for tomorrow instead of today.","TWN":"但在終將完成的樂園，還是不能忘記如何為明天而活。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그렇구나.","JPN":"……そっか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"너도 언제까지고 오늘만 살 생각은 없다는 거네.","JPN":"君もいつまでも今日だけを生きるつもりはないってことだね。","ENG":"So you don't intend to live only for today forever, either.","TWN":"你也不打算永遠只活在今天。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"내일을 맞이하는 것은... 낙원의 주민들, 모두의 바람입니다.","JPN":"明日を迎えるのは……楽園の住民、みんなの願いです。","ENG":"To greet tomorrow... that is the wish of all the residents of the Promised Land.","TWN":"迎來明天……是樂園所有居民的願望。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그것은 낙원이 이루어주지 못하는 유일한 소망이니까요.","JPN":"それは楽園が叶えられない、唯一の願いですから。","ENG":"Because it is the one wish the Promised Land can't grant.","TWN":"因為那是樂園唯一無法實現的願望。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저기, 에클레시아.","JPN":"ねえ、エクレシア。","ENG":"Ecclesia.","TWN":"那個，艾可露西亞。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"예?","JPN":"はい？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"낙원 바깥이 어떤지, 알고 있어?","JPN":"楽園の外はどうなっているか、知ってる？","ENG":"Do you know what it's like outside the Promised Land?","TWN":"你知道樂園外是什麼樣子嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원 너머엔 영원한 겨울이 있습니다. 마왕 타기리온이 남긴 종말의 흔적이라 들었습니다.","JPN":"楽園の向こうは永遠の冬です。魔王タギリオンが残した終末の痕跡と聞きました。","ENG":"Beyond the Promised Land lies an eternal winter. I was told it is the trace of the end left behind by the Demon Lord Thagirion.","TWN":"樂園之外是永遠的冬天，聽說那是魔王塔基里翁留下的末日痕跡。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"흔적 뿐만이 아니야.","JPN":"痕跡だけじゃない。","ENG":"It's not just a trace.","TWN":"不只是痕跡。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저 너머에선 아직도 그 겨울로부터 살아남기 위해, 마왕과 맞서 싸우는 사람들이 있어.","JPN":"あの向こうにはまだその冬で生き残るために、魔王に立ち向かってる人たちがいる。","ENG":"Out there, even now, there are still people fighting the Demon Lord to survive that winter.","TWN":"那裡現在仍有人為了從那場冬天中活下來，與魔王戰鬥。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그럴 리가...","JPN":"そんな……","ENG":"That can't be...","TWN":"不可能……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그럴 리 없사옵니다. 분명 낙원을 제외한 세계는 이미 오래 전 타기리온에게...!","JPN":"そんなはずはございません。楽園を除いて、世界は大昔にタギリオンに……！","ENG":"That can't be true. Surely every world except the Promised Land was long ago destroyed by Thagirion...!","TWN":"不可能的。除了樂園以外的世界，早就被塔基里翁……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온이 세계를 완전히 멸망시켰다면, 어째서 낙원이란 곳은 이토록 온전할 수 있는 걸까?","JPN":"タギリオンが世界を完全に滅亡させたなら、どうして楽園という場所はこんなに元の姿を保っていられるの？","ENG":"If Thagirion had truly destroyed the world completely, then how could a place like the Promised Land remain this intact?","TWN":"如果塔基里翁真的完全毀滅世界，那為什麼樂園還能完好無缺？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...그건...","JPN":"……それは……","ENG":"...That...","TWN":"……那是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이유는 모르겠지만, 이것 하나만은 확실해.","JPN":"理由は分からないけど、一つだけ確かなことがある。","ENG":"I don't know why, but this one thing is certain.","TWN":"我也不知道原因，但我可以肯定一件事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"마왕 타기리온을 막지 못한다면, 머잖아 이곳도 그자의 손에 무너지고 말 거야.","JPN":"魔王タギリオンを阻止できなかったら、もうすぐここもあいつの手によって滅びてしまう。","ENG":"If we fail to stop the Demon Lord Thagirion, this place too will soon collapse by her hand.","TWN":"如果不阻止魔王塔基里翁，這裡不久後也會被她摧毀。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원이 타기리온의 손에...?","JPN":"楽園が、タギリオンの手に……？","ENG":"The Promised Land... by Thagirion's hand...?","TWN":"樂園也會被塔基里翁……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"죽은 성자는 그림자라는 괴물이 되어 망집만 남은 채 떠돌게 되지.","JPN":"死んだ聖者はシャドウという化け物になり、妄執だけが残ったまま彷徨う。","ENG":"A dead Helgon becomes a monster called a Shadow, wandering with nothing left but a lingering obsession.","TWN":"死去的聖者會變成名為暗影的怪物，只剩執念在世間徘徊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"넌 그런 처지가 되어서도, 자신의 긍지를 잃지 않고 타기리온을 막기 위해 분투하던 존재였어.","JPN":"君はそんなことになっても、自分の誇りを忘れずに、タギリオンを止めるために奮闘していた存在だった。","ENG":"Even after ending up that way, you were still someone who never lost your pride and struggled to stop Thagirion.","TWN":"即便如此，你仍然沒有失去自己的尊嚴，一直為了阻止塔基里翁而戰。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"기억이 사라졌다고 해서, 그 긍지마저 사라진 건 아닐 거야.","JPN":"記憶が消えたからって、その誇りまで消えてしまうわけないよ。","ENG":"Just because your memories are gone doesn't mean that pride is gone too.","TWN":"就算記憶消失，你的尊嚴也不會消失。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"과거의 제가 어떤 사람이었는진 모르겠으나...","JPN":"過去のわたくしがどんな人だったのかは分かりませんが……","ENG":"I don't know what kind of person I was in the past...","TWN":"我不知道過去的我是什麼樣的人……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"지금의 저에겐 그 무엇보다 아버지와 함께하는 시간이 가장 소중하옵니다.","JPN":"今のわたくしには、何よりお父様との時間が一番大切でございます。","ENG":"but to me right now, nothing is more precious than the time I spend with my father.","TWN":"但現在的我，最珍惜的就是和父親在一起的時光。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"기억에도 없는 사람들을 지키기 위해 지금 제가 가진 것을 손에서 놓고 싶진 않사옵니다.","JPN":"記憶にもない人たちを守るために、今わたくしが手にしているものを手放したくはありません。","ENG":"I don't wish to let go of what I have now in order to protect people I don't even remember.","TWN":"我不想為了守護那些連記憶都沒有的人，放棄現在擁有的一切。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그건 네 생각이 아니야! 누군가 가짜 기억으로 네 눈과 귀를 가리고 있는 거라고!","JPN":"それは君の思いなんかじゃない！　誰かが偽の記憶で君の目と耳を塞いでるんだよ！","ENG":"That's not your own thought! Someone is covering your eyes and ears with false memories!","TWN":"那不是你的想法！有人用虛假的記憶蒙蔽了你的雙眼和耳朵！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어쩌면 그 벨레스란 자가 그랬을지도 모르지!","JPN":"もしかしたらあのヴェレスって人がそうしたのかもしれない！","ENG":"Maybe that Veles guy did it!","TWN":"也許就是那個叫貝雷斯的人做的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지를 모욕하지 마십시오!","JPN":"お父様を侮辱しないでください！","ENG":"Do not insult my father!","TWN":"請不要侮辱我父親！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"부디...","JPN":"どうか……","ENG":"Please...","TWN":"拜託你……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"제가 사랑하는 이 낙원을... 거짓이라 말하지 말아주십시오.","JPN":"わたくしの愛するこの楽園を……嘘だと言わないでください。","ENG":"Please don't call this Promised Land I love... a lie.","TWN":"不要說我所愛的這個樂園……是假的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"너...","JPN":"君……","ENG":"You...","TWN":"你……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_WIND_07"},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...응?","JPN":"……うん？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"지금... 눈이 내리는 건가?","JPN":"今……雪が降ってるの？","ENG":"Is it... snowing right now?","TWN":"現在……在下雪嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이전보다 더 많이 떨어지고 있사옵니다.","JPN":"前よりたくさん降っております。","ENG":"More is falling than before.","TWN":"比剛才下得更大了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"하지만... 이 시간엔 한 번도 눈이 내린 적이 없는데...?","JPN":"ですが……この時間には一度も雪が降ったことがなかったのに……","ENG":"But... it has never snowed at this hour before...","TWN":"但是……這個時間從來沒有下過雪……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"평소엔 내린 적이 없다고?","JPN":"普段は降ったことがないって？","ENG":"It's never fallen before?","TWN":"你說從來沒有？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"눈 결정이 손에서도 녹지 않아.","JPN":"雪の結晶が手の上でも溶けない。","ENG":"The snowflakes don't melt, even in my hand.","TWN":"雪晶在手上也不會融化。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이건... 대체 무슨 징조인 거지?","JPN":"これは……いったい何の兆しなんだ？","ENG":"What... is this supposed to be a sign of?","TWN":"這……到底是什麼預兆？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"가을 끝무렵의 침묵 속에서, 비로소 낙원은 완성되리라.","JPN":"晩秋の沈黙の中で、ついに楽園は完成されるだろう。","ENG":"Within the silence at the end of autumn, the Promised Land shall at last be complete.","TWN":"在深秋盡頭的寂靜中，樂園終將完成。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"영겁 끝에 맞닥뜨리게 될 첫눈을 맞으며-","JPN":"永劫の果てに迎える初雪とともに……","ENG":"As we welcome the first snowfall we will encounter at the end of eternity...","TWN":"在永恆之終迎來的第一場雪—"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원의 약속은, 그렇게 이루어지리라.","JPN":"楽園の約束は、そうして叶うだろう。","ENG":"Thus shall the promise of the Promised Land be fulfilled.","TWN":"將如此實現樂園的承諾。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원이 약속한 때가 오고 있어요.","JPN":"楽園が約束した時が近づいています。","ENG":"The time promised by the Promised Land is coming.","TWN":"樂園約定的時刻到了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"지금 내리는 눈이 바로 그 증거고요.","JPN":"今降っている雪がその証拠です。","ENG":"And the fact that it is snowing now is the proof of it.","TWN":"現在降下的雪就是證明。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"넌...?","JPN":"君は……？","ENG":"You...?","TWN":"你……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"무의식 깊숙이 박혀있던 차가운 송곳이 움찔대는 것처럼.","JPN":"無意識の奥底に突き刺さっていた冷たい錐が反応するように。","ENG":"As if a cold awl buried deep within my subconscious had twitched.","TWN":"彷彿深埋在意識深處的冰冷尖錐突然顫動。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"낯설고도 익숙한 감각이 마음 한복판을 후벼판다.","JPN":"馴染みがないようでいて馴染み深い感覚が胸の真ん中をえぐる。","ENG":"A strange yet familiar sensation gouges straight through the center of my heart.","TWN":"陌生又熟悉的感覺刺入心底。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"공포, 증오, 동질감, 죄책감, 후회와 연민. 그리고 그 상이한 감정들이 맞부딪히면서 일어나는 혼란이라는 거대한 파도가...","JPN":"恐怖、憎悪、仲間意識、罪悪感、後悔と哀れみ。そしてそれらの異なる感情がぶつかり合いながら起こる混乱という巨大な波が……","ENG":"Fear, hatred, kinship, guilt, regret, pity. And the massive wave of confusion born from all those clashing emotions...","TWN":"恐懼、憎恨、認同感、罪惡感、後悔與憐憫。還有那些彼此碰撞的情緒掀起的巨大混亂浪潮……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"기억의 밑바닥에 오랫동안 가라앉아있던 하나의 이름을 수면 위로 끌어올렸다.","JPN":"記憶の奥底に長い間沈んでいた一つの名を水面まで引き上げた。","ENG":"pulled a name that had long lain sunken at the bottom of my memories up to the surface.","TWN":"讓埋在記憶最深處的名字浮上水面。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...아우드라.","JPN":"……アウドラ。","ENG":"...Audra.","TWN":"……奧德拉。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};